eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   ENCYCLOPEDIA_CATEGORIES: () => (/* binding */ ENCYCLOPEDIA_CATEGORIES),\n/* harmony export */   encyclopediaConcepts: () => (/* binding */ encyclopediaConcepts)\n/* harmony export */ });\nconst ENCYCLOPEDIA_CATEGORIES = [\n    {\n        label: \"Core ML Concepts\",\n        emoji: \"\\uD83E\\uDDE0\",\n        color: \"#22c55e\"\n    },\n    {\n        label: \"Math & Optimization\",\n        emoji: \"\\uD83D\\uDCD0\",\n        color: \"#3b82f6\"\n    },\n    {\n        label: \"Architectures\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        color: \"#eab308\"\n    },\n    {\n        label: \"NLP & Language\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        color: \"#f97316\"\n    },\n    {\n        label: \"Computer Vision\",\n        emoji: \"\\uD83D\\uDC41️\",\n        color: \"#ef4444\"\n    },\n    {\n        label: \"Generative AI\",\n        emoji: \"\\uD83C\\uDFA8\",\n        color: \"#a855f7\"\n    },\n    {\n        label: \"Reinforcement Learning\",\n        emoji: \"\\uD83C\\uDFAE\",\n        color: \"#06b6d4\"\n    },\n    {\n        label: \"MLOps & Infrastructure\",\n        emoji: \"⚙️\",\n        color: \"#64748b\"\n    },\n    {\n        label: \"AI Agents & Applications\",\n        emoji: \"\\uD83E\\uDD16\",\n        color: \"#ec4899\"\n    },\n    {\n        label: \"Safety, Ethics & Governance\",\n        emoji: \"\\uD83D\\uDEE1️\",\n        color: \"#14b8a6\"\n    }\n];\nconst encyclopediaConcepts = [\n    // === Core ML Concepts (1–15) ===\n    {\n        id: \"machine-learning\",\n        concept: \"Machine Learning (ML)\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"A subset of AI where systems learn patterns from data instead of being explicitly programmed. The three main paradigms are supervised, unsupervised, and reinforcement learning.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 1,\n        keyTerms: [\n            \"Training data\",\n            \"Model\",\n            \"Features\",\n            \"Labels\",\n            \"Prediction\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"Google ML Crash Course\",\n                url: \"https://developers.google.com/machine-learning/crash-course\"\n            },\n            {\n                title: \"Andrew Ng's ML Specialization\",\n                url: \"https://www.coursera.org/specializations/machine-learning-introduction\"\n            }\n        ],\n        realWorldApps: \"Spam filtering, recommendation systems, fraud detection, medical diagnosis\"\n    },\n    {\n        id: \"supervised-learning\",\n        concept: \"Supervised Learning\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Learning from labeled examples — the model sees inputs paired with correct outputs and learns to predict outputs for new inputs. Includes classification and regression.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 2,\n        keyTerms: [\n            \"Labels\",\n            \"Classification\",\n            \"Regression\",\n            \"Training set\",\n            \"Test set\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: Supervised Learning\",\n                url: \"https://www.youtube.com/watch?v=nKW8Ndu7Mjw\"\n            }\n        ],\n        realWorldApps: \"Email spam detection, image classification, price prediction, medical diagnosis\"\n    },\n    {\n        id: \"unsupervised-learning\",\n        concept: \"Unsupervised Learning\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Learning patterns from unlabeled data — the model discovers hidden structure without being told the 'right answer'. Includes clustering, dimensionality reduction, and anomaly detection.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 3,\n        keyTerms: [\n            \"Clustering\",\n            \"Dimensionality reduction\",\n            \"Anomaly detection\",\n            \"K-Means\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: K-Means Clustering\",\n                url: \"https://www.youtube.com/watch?v=4b5d3muPQmA\"\n            }\n        ],\n        realWorldApps: \"Customer segmentation, anomaly detection, topic modeling, data compression\"\n    },\n    {\n        id: \"neural-network\",\n        concept: \"Neural Network\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"A computing system inspired by biological brains, composed of layers of interconnected nodes (neurons). Each connection has a weight that's adjusted during training. The foundation of deep learning.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 4,\n        keyTerms: [\n            \"Neurons\",\n            \"Layers\",\n            \"Weights\",\n            \"Bias\",\n            \"Activation function\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"3Blue1Brown: Neural Networks\",\n                url: \"https://www.youtube.com/playlist?list=PLZHQObOWTQDNU6R1_67000Dx_ZCJB-3pi\"\n            },\n            {\n                title: \"Neural Networks & Deep Learning — free book\",\n                url: \"http://neuralnetworksanddeeplearning.com/\"\n            }\n        ],\n        realWorldApps: \"Image recognition, speech synthesis, game playing, autonomous vehicles\"\n    },\n    {\n        id: \"deep-learning\",\n        concept: \"Deep Learning\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"A subset of ML using neural networks with many layers (hence 'deep'). Excels at learning hierarchical representations from raw data — each layer learns increasingly abstract features.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 5,\n        keyTerms: [\n            \"Hidden layers\",\n            \"Feature hierarchy\",\n            \"Representation learning\",\n            \"End-to-end learning\"\n        ],\n        prerequisites: [\n            \"Neural Network\"\n        ],\n        learnMore: [\n            {\n                title: \"fast.ai — Practical Deep Learning\",\n                url: \"https://course.fast.ai/\"\n            },\n            {\n                title: \"Dive into Deep Learning\",\n                url: \"https://d2l.ai\"\n            }\n        ],\n        realWorldApps: \"Self-driving cars, language translation, drug discovery, artistic generation\"\n    },\n    {\n        id: \"features-labels\",\n        concept: \"Features & Labels\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Features are the input variables (columns) used to make predictions. Labels are the output variable (what you're trying to predict). Feature engineering — crafting good inputs — is often more important than the model choice.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 6,\n        keyTerms: [\n            \"Feature vector\",\n            \"Target variable\",\n            \"Feature engineering\",\n            \"Feature selection\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"Google: Feature Engineering\",\n                url: \"https://developers.google.com/machine-learning/data-prep/transform/transform-numeric\"\n            }\n        ],\n        realWorldApps: \"Any ML system — choosing the right features determines model quality\"\n    },\n    {\n        id: \"overfitting-underfitting\",\n        concept: \"Overfitting & Underfitting\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Overfitting: the model memorizes training data but fails on new data (too complex). Underfitting: the model is too simple to capture patterns. The goal is the sweet spot — generalizing well to unseen data.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 7,\n        keyTerms: [\n            \"Generalization\",\n            \"Training error\",\n            \"Validation error\",\n            \"Model complexity\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: Overfitting & Underfitting\",\n                url: \"https://www.youtube.com/watch?v=EuBBz3bI-aA\"\n            }\n        ]\n    },\n    {\n        id: \"bias-variance\",\n        concept: \"Bias-Variance Tradeoff\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Bias: error from overly simplistic assumptions (underfitting). Variance: error from sensitivity to training data fluctuations (overfitting). The tradeoff is fundamental — reducing one often increases the other.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"intermediate\",\n        rank: 8,\n        keyTerms: [\n            \"Bias\",\n            \"Variance\",\n            \"Tradeoff\",\n            \"Model complexity\",\n            \"Generalization\"\n        ],\n        prerequisites: [\n            \"Overfitting & Underfitting\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: Bias-Variance\",\n                url: \"https://www.youtube.com/watch?v=EuBBz3bI-aA\"\n            }\n        ]\n    },\n    {\n        id: \"classification-regression\",\n        concept: \"Classification vs Regression\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Classification predicts discrete categories (spam/not spam, cat/dog). Regression predicts continuous values (price, temperature). The choice depends on whether your output is a category or a number.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 9,\n        keyTerms: [\n            \"Binary classification\",\n            \"Multi-class\",\n            \"Linear regression\",\n            \"Logistic regression\"\n        ],\n        prerequisites: [\n            \"Supervised Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: Linear Regression\",\n                url: \"https://www.youtube.com/watch?v=PaFPbb66DxQ\"\n            }\n        ],\n        realWorldApps: \"Disease diagnosis (classification), house price prediction (regression)\"\n    },\n    {\n        id: \"transfer-learning\",\n        concept: \"Transfer Learning\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Using a model trained on one task as the starting point for a different task. Instead of training from scratch, you fine-tune a pretrained model — dramatically reducing data and compute requirements.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"intermediate\",\n        rank: 10,\n        keyTerms: [\n            \"Pre-training\",\n            \"Fine-tuning\",\n            \"Domain adaptation\",\n            \"Feature extraction\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Transfer Learning — CS231n\",\n                url: \"https://cs231n.github.io/transfer-learning/\"\n            }\n        ],\n        realWorldApps: \"Medical imaging with limited data, NLP with pretrained LLMs, custom image classifiers\"\n    },\n    {\n        id: \"training-inference\",\n        concept: \"Training vs Inference\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Training: the process of learning from data (expensive, slow, uses GPUs). Inference: using the trained model to make predictions (fast, cheap). Understanding this distinction is key to ML economics.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 11,\n        keyTerms: [\n            \"Training loop\",\n            \"Forward pass\",\n            \"Batch size\",\n            \"Epoch\",\n            \"Latency\"\n        ],\n        prerequisites: [\n            \"Neural Network\"\n        ],\n        learnMore: [\n            {\n                title: \"NVIDIA: Training vs Inference\",\n                url: \"https://blogs.nvidia.com/blog/whats-the-difference-between-deep-learning-training-and-inference-ai-explained/\"\n            }\n        ]\n    },\n    {\n        id: \"regularization\",\n        concept: \"Regularization\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Techniques to prevent overfitting by adding constraints to the model. L1 (Lasso) drives weights to zero for feature selection. L2 (Ridge) penalizes large weights. Dropout randomly disables neurons during training.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"intermediate\",\n        rank: 12,\n        keyTerms: [\n            \"L1/Lasso\",\n            \"L2/Ridge\",\n            \"Dropout\",\n            \"Early stopping\",\n            \"Weight decay\"\n        ],\n        prerequisites: [\n            \"Overfitting & Underfitting\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: Regularization\",\n                url: \"https://www.youtube.com/watch?v=Q81RR3yKn30\"\n            }\n        ]\n    },\n    {\n        id: \"few-shot-zero-shot\",\n        concept: \"Few-Shot & Zero-Shot Learning\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"Few-shot: learning from just a handful of examples. Zero-shot: performing tasks with no examples, using only a description. LLMs excel at both — GPT-3 showed that scale enables few-shot learning.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"intermediate\",\n        rank: 13,\n        keyTerms: [\n            \"In-context learning\",\n            \"Prompt engineering\",\n            \"Meta-learning\",\n            \"Generalization\"\n        ],\n        prerequisites: [\n            \"Transfer Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"GPT-3 Paper: Language Models are Few-Shot Learners\",\n                url: \"https://arxiv.org/abs/2005.14165\"\n            }\n        ],\n        realWorldApps: \"Chatbots answering novel questions, classifying with minimal labeled data\"\n    },\n    {\n        id: \"linear-regression\",\n        concept: \"Linear Regression\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"The simplest ML model — fits a straight line (or hyperplane) through data points to predict a continuous value. Despite its simplicity, it's the starting point for understanding all regression models.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"beginner\",\n        rank: 14,\n        keyTerms: [\n            \"Slope\",\n            \"Intercept\",\n            \"Least squares\",\n            \"R-squared\",\n            \"Coefficients\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"StatQuest: Linear Regression\",\n                url: \"https://www.youtube.com/watch?v=PaFPbb66DxQ\"\n            }\n        ]\n    },\n    {\n        id: \"semi-supervised\",\n        concept: \"Semi-Supervised Learning\",\n        emoji: \"\\uD83E\\uDDE0\",\n        description: \"A hybrid approach using a small amount of labeled data with a large amount of unlabeled data. Leverages the structure in unlabeled data to improve learning — practical when labeling is expensive.\",\n        category: \"Core ML Concepts\",\n        difficulty: \"intermediate\",\n        rank: 15,\n        keyTerms: [\n            \"Pseudo-labels\",\n            \"Self-training\",\n            \"Consistency regularization\"\n        ],\n        prerequisites: [\n            \"Supervised Learning\",\n            \"Unsupervised Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Semi-Supervised Learning — Google\",\n                url: \"https://ai.google/research/pubs/pub41473\"\n            }\n        ]\n    },\n    // === Math & Optimization (16–25) ===\n    {\n        id: \"gradient-descent\",\n        concept: \"Gradient Descent\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"The fundamental optimization algorithm for training neural networks. It iteratively adjusts model parameters in the direction that reduces the loss function — like walking downhill to find the valley.\",\n        category: \"Math & Optimization\",\n        difficulty: \"beginner\",\n        rank: 16,\n        keyTerms: [\n            \"Learning rate\",\n            \"Stochastic gradient descent (SGD)\",\n            \"Minibatch\",\n            \"Convergence\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"3Blue1Brown: Gradient Descent\",\n                url: \"https://www.youtube.com/watch?v=IHZwWFHWa-w\"\n            }\n        ]\n    },\n    {\n        id: \"backpropagation\",\n        concept: \"Backpropagation\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"The algorithm for computing gradients in neural networks by propagating errors backward through layers. Popularized by Hinton in 1986, it's the engine that makes deep learning possible.\",\n        category: \"Math & Optimization\",\n        difficulty: \"intermediate\",\n        rank: 17,\n        keyTerms: [\n            \"Chain rule\",\n            \"Computational graph\",\n            \"Gradient flow\",\n            \"Autograd\"\n        ],\n        prerequisites: [\n            \"Gradient Descent\",\n            \"Neural Network\"\n        ],\n        learnMore: [\n            {\n                title: \"3Blue1Brown: Backpropagation\",\n                url: \"https://www.youtube.com/watch?v=Ilg3gGewQ5U\"\n            },\n            {\n                title: \"Karpathy: Backprop Ninja\",\n                url: \"https://www.youtube.com/watch?v=q8SA3rM6ckI\"\n            }\n        ]\n    },\n    {\n        id: \"loss-function\",\n        concept: \"Loss Function\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"A function that measures how wrong the model's predictions are. Training = minimizing the loss. Common losses: MSE (regression), cross-entropy (classification), contrastive (embeddings).\",\n        category: \"Math & Optimization\",\n        difficulty: \"beginner\",\n        rank: 18,\n        keyTerms: [\n            \"MSE\",\n            \"Cross-entropy\",\n            \"Contrastive loss\",\n            \"Objective function\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: Cross Entropy\",\n                url: \"https://www.youtube.com/watch?v=6ArSys5qHAU\"\n            }\n        ]\n    },\n    {\n        id: \"activation-functions\",\n        concept: \"Activation Functions\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"Non-linear functions applied to neuron outputs — they give neural networks the ability to learn complex patterns. ReLU, Sigmoid, Tanh, GELU, and Swish are the most common.\",\n        category: \"Math & Optimization\",\n        difficulty: \"beginner\",\n        rank: 19,\n        keyTerms: [\n            \"ReLU\",\n            \"Sigmoid\",\n            \"Tanh\",\n            \"GELU\",\n            \"Vanishing gradient\"\n        ],\n        prerequisites: [\n            \"Neural Network\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: ReLU\",\n                url: \"https://www.youtube.com/watch?v=68BZ5f7P94Q\"\n            }\n        ]\n    },\n    {\n        id: \"embeddings\",\n        concept: \"Embeddings\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"Dense vector representations that capture semantic meaning. Words, images, and even users can be embedded into continuous vector spaces where similar items are close together.\",\n        category: \"Math & Optimization\",\n        difficulty: \"intermediate\",\n        rank: 20,\n        keyTerms: [\n            \"Word2Vec\",\n            \"GloVe\",\n            \"Embedding space\",\n            \"Cosine similarity\",\n            \"Dimensionality\"\n        ],\n        prerequisites: [\n            \"Neural Network\"\n        ],\n        learnMore: [\n            {\n                title: \"Jay Alammar: Illustrated Word2Vec\",\n                url: \"https://jalammar.github.io/illustrated-word2vec/\"\n            }\n        ],\n        realWorldApps: \"Search engines, recommendation systems, RAG, semantic similarity\"\n    },\n    {\n        id: \"dimensionality-reduction\",\n        concept: \"Dimensionality Reduction\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"Reducing the number of features while preserving important information. PCA, t-SNE, and UMAP are the main techniques — essential for visualization and fighting the curse of dimensionality.\",\n        category: \"Math & Optimization\",\n        difficulty: \"intermediate\",\n        rank: 21,\n        keyTerms: [\n            \"PCA\",\n            \"t-SNE\",\n            \"UMAP\",\n            \"Curse of dimensionality\",\n            \"Feature compression\"\n        ],\n        prerequisites: [\n            \"Unsupervised Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: PCA\",\n                url: \"https://www.youtube.com/watch?v=FgakZw6K1QQ\"\n            }\n        ]\n    },\n    {\n        id: \"feature-engineering\",\n        concept: \"Feature Engineering\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"The art of creating, transforming, and selecting input features to improve model performance. Often more impactful than model choice — 'garbage in, garbage out' applies doubly to ML.\",\n        category: \"Math & Optimization\",\n        difficulty: \"intermediate\",\n        rank: 22,\n        keyTerms: [\n            \"Feature scaling\",\n            \"One-hot encoding\",\n            \"Feature crosses\",\n            \"Polynomial features\"\n        ],\n        prerequisites: [\n            \"Features & Labels\"\n        ],\n        learnMore: [\n            {\n                title: \"Kaggle: Feature Engineering\",\n                url: \"https://www.kaggle.com/learn/feature-engineering\"\n            }\n        ]\n    },\n    {\n        id: \"k-means\",\n        concept: \"K-Means Clustering\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"The simplest clustering algorithm — assigns data points to K groups by iteratively moving cluster centers to minimize within-cluster distances. Fast, intuitive, but requires choosing K upfront.\",\n        category: \"Math & Optimization\",\n        difficulty: \"beginner\",\n        rank: 23,\n        keyTerms: [\n            \"Centroids\",\n            \"Elbow method\",\n            \"Inertia\",\n            \"K selection\"\n        ],\n        prerequisites: [\n            \"Unsupervised Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: K-Means\",\n                url: \"https://www.youtube.com/watch?v=4b5d3muPQmA\"\n            }\n        ]\n    },\n    {\n        id: \"anomaly-detection\",\n        concept: \"Anomaly Detection\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"Identifying rare, unusual data points that differ significantly from the majority. Critical for fraud detection, cybersecurity, manufacturing defects, and health monitoring.\",\n        category: \"Math & Optimization\",\n        difficulty: \"intermediate\",\n        rank: 24,\n        keyTerms: [\n            \"Outlier\",\n            \"Isolation Forest\",\n            \"Autoencoder\",\n            \"Statistical threshold\"\n        ],\n        prerequisites: [\n            \"Unsupervised Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"scikit-learn: Anomaly Detection\",\n                url: \"https://scikit-learn.org/stable/modules/outlier_detection.html\"\n            }\n        ],\n        realWorldApps: \"Credit card fraud, network intrusion, equipment failure prediction\"\n    },\n    {\n        id: \"boosting\",\n        concept: \"Boosting (XGBoost, LightGBM)\",\n        emoji: \"\\uD83D\\uDCD0\",\n        description: \"An ensemble technique that combines many weak learners (usually decision trees) sequentially, with each new tree correcting the errors of previous ones. XGBoost and LightGBM dominate Kaggle competitions.\",\n        category: \"Math & Optimization\",\n        difficulty: \"intermediate\",\n        rank: 25,\n        keyTerms: [\n            \"Gradient boosting\",\n            \"XGBoost\",\n            \"LightGBM\",\n            \"CatBoost\",\n            \"Ensemble\"\n        ],\n        prerequisites: [\n            \"Supervised Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"StatQuest: XGBoost\",\n                url: \"https://www.youtube.com/watch?v=OtD8wVaFm6E\"\n            }\n        ],\n        realWorldApps: \"Tabular data competitions, ranking systems, click prediction\"\n    },\n    // === Architectures (26–40) ===\n    {\n        id: \"transformer\",\n        concept: \"Transformer Architecture\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"THE architecture that changed everything (2017). Uses self-attention to process sequences in parallel, replacing RNNs. Foundation of GPT, BERT, and virtually every modern AI system.\",\n        category: \"Architectures\",\n        difficulty: \"intermediate\",\n        rank: 26,\n        keyTerms: [\n            \"Self-attention\",\n            \"Multi-head attention\",\n            \"Positional encoding\",\n            \"Encoder-decoder\"\n        ],\n        prerequisites: [\n            \"Neural Network\",\n            \"Attention Mechanism\"\n        ],\n        learnMore: [\n            {\n                title: \"The Illustrated Transformer — Jay Alammar\",\n                url: \"https://jalammar.github.io/illustrated-transformer/\"\n            },\n            {\n                title: \"Attention Is All You Need (paper)\",\n                url: \"https://arxiv.org/abs/1706.03762\"\n            }\n        ]\n    },\n    {\n        id: \"attention-mechanism\",\n        concept: \"Attention Mechanism\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"A technique allowing models to focus on relevant parts of input when producing output. Self-attention (in Transformers) lets each position attend to all other positions in a sequence.\",\n        category: \"Architectures\",\n        difficulty: \"intermediate\",\n        rank: 27,\n        keyTerms: [\n            \"Query\",\n            \"Key\",\n            \"Value\",\n            \"Attention weights\",\n            \"Softmax\"\n        ],\n        prerequisites: [\n            \"Neural Network\"\n        ],\n        learnMore: [\n            {\n                title: \"Jay Alammar: Illustrated Attention\",\n                url: \"https://jalammar.github.io/visualizing-neural-machine-translation-mechanics-of-seq2seq-models-with-attention/\"\n            }\n        ]\n    },\n    {\n        id: \"self-attention\",\n        concept: \"Self-Attention\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"A special case of attention where a sequence attends to itself — each token computes relationships with every other token. This is the core mechanism powering Transformers.\",\n        category: \"Architectures\",\n        difficulty: \"intermediate\",\n        rank: 28,\n        keyTerms: [\n            \"QKV matrices\",\n            \"Attention score\",\n            \"Multi-head\",\n            \"Causal masking\"\n        ],\n        prerequisites: [\n            \"Attention Mechanism\"\n        ],\n        learnMore: [\n            {\n                title: \"Karpathy: Let's build GPT\",\n                url: \"https://www.youtube.com/watch?v=kCc8FmEb1nY\"\n            }\n        ]\n    },\n    {\n        id: \"cnn\",\n        concept: \"Convolutional Neural Network (CNN)\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"Architecture designed for grid-like data (images). Uses learned filters (kernels) to detect features at different scales — edges → textures → objects. Revolutionized computer vision.\",\n        category: \"Architectures\",\n        difficulty: \"intermediate\",\n        rank: 29,\n        keyTerms: [\n            \"Convolution\",\n            \"Kernel\",\n            \"Pooling\",\n            \"Feature map\",\n            \"Stride\"\n        ],\n        prerequisites: [\n            \"Neural Network\"\n        ],\n        learnMore: [\n            {\n                title: \"CNN Explainer — Interactive Visualization\",\n                url: \"https://poloclub.github.io/cnn-explainer/\"\n            },\n            {\n                title: \"Stanford CS231n\",\n                url: \"https://cs231n.github.io/\"\n            }\n        ]\n    },\n    {\n        id: \"rnn\",\n        concept: \"Recurrent Neural Network (RNN)\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"Architecture for sequential data that maintains a hidden state across time steps. Suffers from vanishing gradients for long sequences — largely replaced by Transformers but still relevant for understanding.\",\n        category: \"Architectures\",\n        difficulty: \"intermediate\",\n        rank: 30,\n        keyTerms: [\n            \"Hidden state\",\n            \"Vanishing gradient\",\n            \"Sequence-to-sequence\",\n            \"Time steps\"\n        ],\n        prerequisites: [\n            \"Neural Network\"\n        ],\n        learnMore: [\n            {\n                title: \"Colah: Understanding LSTMs\",\n                url: \"https://colah.github.io/posts/2015-08-Understanding-LSTMs/\"\n            }\n        ]\n    },\n    {\n        id: \"lstm\",\n        concept: \"LSTM (Long Short-Term Memory)\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"An RNN variant that solves the vanishing gradient problem using gates (forget, input, output) that control information flow. Was the dominant sequence architecture before Transformers.\",\n        category: \"Architectures\",\n        difficulty: \"intermediate\",\n        rank: 31,\n        keyTerms: [\n            \"Forget gate\",\n            \"Input gate\",\n            \"Output gate\",\n            \"Cell state\",\n            \"GRU\"\n        ],\n        prerequisites: [\n            \"RNN\"\n        ],\n        learnMore: [\n            {\n                title: \"Colah: Understanding LSTMs (MUST READ)\",\n                url: \"https://colah.github.io/posts/2015-08-Understanding-LSTMs/\"\n            }\n        ]\n    },\n    {\n        id: \"gpt\",\n        concept: \"GPT (Generative Pre-trained Transformer)\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"A decoder-only Transformer trained to predict the next token. GPT-1 → GPT-2 → GPT-3 → GPT-4 showed that scaling this simple idea produces increasingly capable AI. The architecture behind ChatGPT.\",\n        category: \"Architectures\",\n        difficulty: \"intermediate\",\n        rank: 32,\n        keyTerms: [\n            \"Autoregressive\",\n            \"Next-token prediction\",\n            \"Decoder-only\",\n            \"Scaling laws\"\n        ],\n        prerequisites: [\n            \"Transformer Architecture\"\n        ],\n        learnMore: [\n            {\n                title: \"Jay Alammar: Illustrated GPT-2\",\n                url: \"https://jalammar.github.io/illustrated-gpt2/\"\n            },\n            {\n                title: \"Karpathy: nanoGPT\",\n                url: \"https://github.com/karpathy/nanoGPT\"\n            }\n        ]\n    },\n    {\n        id: \"bert\",\n        concept: \"BERT (Bidirectional Encoder)\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"An encoder-only Transformer that reads text bidirectionally (both left-to-right and right-to-left). Trained with masked language modeling. Dominates classification, NER, and search/ranking tasks.\",\n        category: \"Architectures\",\n        difficulty: \"intermediate\",\n        rank: 33,\n        keyTerms: [\n            \"Masked language modeling\",\n            \"Encoder-only\",\n            \"Bidirectional context\",\n            \"Fine-tuning\"\n        ],\n        prerequisites: [\n            \"Transformer Architecture\"\n        ],\n        learnMore: [\n            {\n                title: \"Jay Alammar: Illustrated BERT\",\n                url: \"https://jalammar.github.io/illustrated-bert/\"\n            }\n        ],\n        realWorldApps: \"Google Search, sentiment analysis, document classification, question answering\"\n    },\n    {\n        id: \"ssm-mamba\",\n        concept: \"State Space Models (Mamba)\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"An alternative to Transformers that processes sequences with linear-time complexity instead of quadratic attention. Mamba and S4 are leading SSM architectures, offering advantages for very long sequences.\",\n        category: \"Architectures\",\n        difficulty: \"advanced\",\n        rank: 34,\n        keyTerms: [\n            \"Linear complexity\",\n            \"Selective SSM\",\n            \"S4\",\n            \"Long-range dependencies\"\n        ],\n        prerequisites: [\n            \"Transformer Architecture\"\n        ],\n        learnMore: [\n            {\n                title: \"Mamba Paper\",\n                url: \"https://arxiv.org/abs/2312.00752\"\n            }\n        ]\n    },\n    {\n        id: \"vision-transformer\",\n        concept: \"Vision Transformer (ViT)\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"Applying the Transformer architecture to images by splitting them into patches and treating each patch as a token. Showed that attention can match or exceed CNNs for vision tasks at scale.\",\n        category: \"Architectures\",\n        difficulty: \"advanced\",\n        rank: 35,\n        keyTerms: [\n            \"Patch embedding\",\n            \"Position embedding\",\n            \"CLS token\",\n            \"Image patches\"\n        ],\n        prerequisites: [\n            \"Transformer Architecture\",\n            \"CNN\"\n        ],\n        learnMore: [\n            {\n                title: \"ViT Paper — An Image is Worth 16x16 Words\",\n                url: \"https://arxiv.org/abs/2010.11929\"\n            }\n        ]\n    },\n    {\n        id: \"multimodal-models\",\n        concept: \"Multimodal Models\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"AI models that process multiple types of data — text, images, audio, video — simultaneously. GPT-4V, Gemini, and Claude 3 are multimodal. The future of AI is not text-only.\",\n        category: \"Architectures\",\n        difficulty: \"advanced\",\n        rank: 36,\n        keyTerms: [\n            \"Cross-modal attention\",\n            \"Vision-language\",\n            \"Contrastive learning\",\n            \"CLIP\"\n        ],\n        prerequisites: [\n            \"Transformer Architecture\"\n        ],\n        learnMore: [\n            {\n                title: \"CLIP Paper — OpenAI\",\n                url: \"https://arxiv.org/abs/2103.00020\"\n            }\n        ],\n        realWorldApps: \"Image captioning, visual Q&A, document understanding, video analysis\"\n    },\n    {\n        id: \"knowledge-distillation\",\n        concept: \"Knowledge Distillation\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"Training a smaller 'student' model to mimic a larger 'teacher' model's behavior. The student learns from the teacher's soft outputs (probabilities), capturing knowledge that's lost with hard labels alone.\",\n        category: \"Architectures\",\n        difficulty: \"advanced\",\n        rank: 37,\n        keyTerms: [\n            \"Teacher model\",\n            \"Student model\",\n            \"Soft labels\",\n            \"Temperature scaling\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Distilling the Knowledge in a Neural Network — Hinton\",\n                url: \"https://arxiv.org/abs/1503.02531\"\n            }\n        ]\n    },\n    {\n        id: \"quantization\",\n        concept: \"Model Quantization & Compression\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"Reducing model size and computational cost by using lower-precision numbers (e.g., 32-bit → 4-bit floats). Enables running LLMs on consumer hardware. GPTQ, GGUF, and AWQ are popular methods.\",\n        category: \"Architectures\",\n        difficulty: \"advanced\",\n        rank: 38,\n        keyTerms: [\n            \"INT8\",\n            \"INT4\",\n            \"GPTQ\",\n            \"GGUF\",\n            \"AWQ\",\n            \"Mixed precision\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Hugging Face: Quantization Guide\",\n                url: \"https://huggingface.co/docs/transformers/quantization\"\n            }\n        ],\n        realWorldApps: \"Running LLMs locally, mobile AI, edge deployment\"\n    },\n    {\n        id: \"nas\",\n        concept: \"Neural Architecture Search (NAS)\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"Using AI to design AI architectures. Instead of hand-designing networks, NAS automatically searches for optimal architectures — the meta approach to building neural networks.\",\n        category: \"Architectures\",\n        difficulty: \"advanced\",\n        rank: 39,\n        keyTerms: [\n            \"Search space\",\n            \"Controller\",\n            \"Reinforcement learning NAS\",\n            \"EfficientNet\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Neural Architecture Search — Google AI Blog\",\n                url: \"https://ai.googleblog.com/2017/05/using-machine-learning-to-explore.html\"\n            }\n        ]\n    },\n    {\n        id: \"neuro-symbolic\",\n        concept: \"Neuro-Symbolic AI\",\n        emoji: \"\\uD83C\\uDFD7️\",\n        description: \"Combining neural networks (learning from data) with symbolic AI (logical reasoning). Aims to get the best of both worlds — learning ability plus interpretable, compositional reasoning.\",\n        category: \"Architectures\",\n        difficulty: \"advanced\",\n        rank: 40,\n        keyTerms: [\n            \"Symbolic reasoning\",\n            \"Knowledge graphs\",\n            \"Logical rules\",\n            \"Hybrid systems\"\n        ],\n        prerequisites: [\n            \"Neural Network\"\n        ],\n        learnMore: [\n            {\n                title: \"Gary Marcus: The Next Decade in AI\",\n                url: \"https://arxiv.org/abs/2002.06177\"\n            }\n        ]\n    },\n    // === NLP & Language (41–55) ===\n    {\n        id: \"nlp\",\n        concept: \"Natural Language Processing (NLP)\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"The branch of AI focused on enabling computers to understand, interpret, and generate human language. Encompasses tasks from sentiment analysis to machine translation to question answering.\",\n        category: \"NLP & Language\",\n        difficulty: \"beginner\",\n        rank: 41,\n        keyTerms: [\n            \"Tokenization\",\n            \"Parsing\",\n            \"NER\",\n            \"Sentiment analysis\",\n            \"Machine translation\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Hugging Face NLP Course (Free)\",\n                url: \"https://huggingface.co/learn/nlp-course\"\n            },\n            {\n                title: \"Stanford CS224n\",\n                url: \"https://web.stanford.edu/class/cs224n/\"\n            }\n        ]\n    },\n    {\n        id: \"tokenization\",\n        concept: \"Tokenization\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"Breaking text into smaller units (tokens) for processing. Modern tokenizers use subword methods (BPE, SentencePiece) — 'unhappiness' → ['un', 'happiness']. Token count determines cost and context window usage.\",\n        category: \"NLP & Language\",\n        difficulty: \"beginner\",\n        rank: 42,\n        keyTerms: [\n            \"BPE\",\n            \"SentencePiece\",\n            \"WordPiece\",\n            \"Token\",\n            \"Vocabulary\"\n        ],\n        prerequisites: [\n            \"NLP\"\n        ],\n        learnMore: [\n            {\n                title: \"Hugging Face: Tokenizers\",\n                url: \"https://huggingface.co/learn/nlp-course/chapter6/1\"\n            }\n        ]\n    },\n    {\n        id: \"word2vec\",\n        concept: \"Word2Vec & Word Embeddings\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"Representing words as dense vectors where semantic relationships are captured geometrically. The famous result: king - man + woman ≈ queen. Predecessor to modern embeddings used in LLMs.\",\n        category: \"NLP & Language\",\n        difficulty: \"intermediate\",\n        rank: 43,\n        keyTerms: [\n            \"Skip-gram\",\n            \"CBOW\",\n            \"GloVe\",\n            \"Cosine similarity\",\n            \"Embedding space\"\n        ],\n        prerequisites: [\n            \"Embeddings\"\n        ],\n        learnMore: [\n            {\n                title: \"Jay Alammar: Illustrated Word2Vec\",\n                url: \"https://jalammar.github.io/illustrated-word2vec/\"\n            }\n        ]\n    },\n    {\n        id: \"prompt-engineering\",\n        concept: \"Prompt Engineering\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"The art and science of crafting inputs to LLMs to get optimal outputs. Techniques include zero-shot, few-shot, chain-of-thought, ReAct, and system prompts. The most practical AI skill of 2025–2026.\",\n        category: \"NLP & Language\",\n        difficulty: \"beginner\",\n        rank: 44,\n        keyTerms: [\n            \"Zero-shot\",\n            \"Few-shot\",\n            \"Chain-of-thought\",\n            \"System prompt\",\n            \"Temperature\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"Anthropic Prompt Engineering Guide\",\n                url: \"https://docs.anthropic.com/en/docs/build-with-claude/prompt-engineering/overview\"\n            },\n            {\n                title: \"OpenAI Prompt Engineering Guide\",\n                url: \"https://platform.openai.com/docs/guides/prompt-engineering\"\n            }\n        ],\n        realWorldApps: \"Every interaction with ChatGPT, Claude, Gemini — it's the universal AI interface\"\n    },\n    {\n        id: \"rag\",\n        concept: \"Retrieval-Augmented Generation (RAG)\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"Combining LLMs with external knowledge retrieval. Instead of relying solely on training data, RAG retrieves relevant documents and passes them to the LLM — reducing hallucinations and adding current information.\",\n        category: \"NLP & Language\",\n        difficulty: \"intermediate\",\n        rank: 45,\n        keyTerms: [\n            \"Retriever\",\n            \"Generator\",\n            \"Vector search\",\n            \"Chunking\",\n            \"Context window\"\n        ],\n        prerequisites: [\n            \"Embeddings\",\n            \"Transformer Architecture\"\n        ],\n        learnMore: [\n            {\n                title: \"RAG Paper — Meta\",\n                url: \"https://arxiv.org/abs/2005.11401\"\n            },\n            {\n                title: \"LangChain RAG Tutorial\",\n                url: \"https://python.langchain.com/docs/tutorials/rag/\"\n            }\n        ],\n        realWorldApps: \"Enterprise chatbots, document Q&A, customer support, legal research\"\n    },\n    {\n        id: \"fine-tuning\",\n        concept: \"Fine-Tuning LLMs\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"Adapting a pretrained LLM to a specific task or domain by training on additional data. LoRA and QLoRA enable efficient fine-tuning by only updating a small fraction of parameters.\",\n        category: \"NLP & Language\",\n        difficulty: \"advanced\",\n        rank: 46,\n        keyTerms: [\n            \"LoRA\",\n            \"QLoRA\",\n            \"PEFT\",\n            \"Instruction tuning\",\n            \"Adapter layers\"\n        ],\n        prerequisites: [\n            \"Transfer Learning\",\n            \"Transformer Architecture\"\n        ],\n        learnMore: [\n            {\n                title: \"LoRA Paper\",\n                url: \"https://arxiv.org/abs/2106.09685\"\n            },\n            {\n                title: \"Hugging Face PEFT\",\n                url: \"https://huggingface.co/docs/peft\"\n            }\n        ]\n    },\n    {\n        id: \"chain-of-thought\",\n        concept: \"Chain-of-Thought Reasoning\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"A prompting technique where the model 'shows its work' by reasoning step-by-step before answering. Dramatically improves performance on math, logic, and complex reasoning tasks.\",\n        category: \"NLP & Language\",\n        difficulty: \"intermediate\",\n        rank: 47,\n        keyTerms: [\n            \"Step-by-step reasoning\",\n            \"Scratchpad\",\n            \"Tree-of-thought\",\n            \"Self-consistency\"\n        ],\n        prerequisites: [\n            \"Prompt Engineering\"\n        ],\n        learnMore: [\n            {\n                title: \"Chain-of-Thought Paper — Google (2022)\",\n                url: \"https://arxiv.org/abs/2201.11903\"\n            }\n        ]\n    },\n    {\n        id: \"vector-databases\",\n        concept: \"Vector Databases\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"Specialized databases optimized for storing and searching high-dimensional vectors (embeddings). Enable fast similarity search — the backbone of RAG, recommendation systems, and semantic search.\",\n        category: \"NLP & Language\",\n        difficulty: \"intermediate\",\n        rank: 48,\n        keyTerms: [\n            \"HNSW\",\n            \"ANN search\",\n            \"Cosine similarity\",\n            \"Pinecone\",\n            \"ChromaDB\",\n            \"Weaviate\"\n        ],\n        prerequisites: [\n            \"Embeddings\"\n        ],\n        learnMore: [\n            {\n                title: \"Pinecone: What are Vector Databases?\",\n                url: \"https://www.pinecone.io/learn/vector-database/\"\n            }\n        ],\n        realWorldApps: \"RAG systems, recommendation engines, image search, semantic search\"\n    },\n    {\n        id: \"llm-scaling\",\n        concept: \"LLM Scaling Laws\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"The empirical finding that LLM performance improves predictably with more data, compute, and parameters. Chinchilla scaling laws (2022) showed that most models were undertrained relative to their size.\",\n        category: \"NLP & Language\",\n        difficulty: \"advanced\",\n        rank: 49,\n        keyTerms: [\n            \"Chinchilla\",\n            \"Compute-optimal\",\n            \"Emergent abilities\",\n            \"Power law\"\n        ],\n        prerequisites: [\n            \"GPT\"\n        ],\n        learnMore: [\n            {\n                title: \"Chinchilla Paper — DeepMind\",\n                url: \"https://arxiv.org/abs/2203.15556\"\n            }\n        ]\n    },\n    {\n        id: \"rlhf\",\n        concept: \"RLHF (Reinforcement Learning from Human Feedback)\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"The technique that made ChatGPT helpful and safe. Trains a reward model on human preferences, then optimizes the LLM against it. The key ingredient between a base model and a useful assistant.\",\n        category: \"NLP & Language\",\n        difficulty: \"advanced\",\n        rank: 50,\n        keyTerms: [\n            \"Reward model\",\n            \"PPO\",\n            \"Preference data\",\n            \"Constitutional AI\",\n            \"DPO\"\n        ],\n        prerequisites: [\n            \"Fine-Tuning LLMs\",\n            \"Reinforcement Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"InstructGPT Paper — OpenAI\",\n                url: \"https://arxiv.org/abs/2203.02155\"\n            },\n            {\n                title: \"Hugging Face TRL\",\n                url: \"https://huggingface.co/docs/trl\"\n            }\n        ]\n    },\n    {\n        id: \"context-window\",\n        concept: \"Context Window & Long Context\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"The maximum number of tokens an LLM can process at once. GPT-4 Turbo: 128K tokens. Claude 3: 200K tokens. Gemini 1.5: 1M+ tokens. Longer context enables processing entire codebases and books.\",\n        category: \"NLP & Language\",\n        difficulty: \"intermediate\",\n        rank: 51,\n        keyTerms: [\n            \"Token limit\",\n            \"Context length\",\n            \"Needle-in-a-haystack\",\n            \"KV cache\"\n        ],\n        prerequisites: [\n            \"Tokenization\",\n            \"Transformer Architecture\"\n        ],\n        learnMore: [\n            {\n                title: \"Anthropic: Long Context\",\n                url: \"https://www.anthropic.com/research/many-shot-jailbreaking\"\n            }\n        ]\n    },\n    {\n        id: \"text-generation\",\n        concept: \"Text Generation & Sampling\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"How LLMs produce text — sampling from probability distributions over tokens. Temperature controls randomness. Top-k and top-p (nucleus) sampling balance creativity and coherence.\",\n        category: \"NLP & Language\",\n        difficulty: \"intermediate\",\n        rank: 52,\n        keyTerms: [\n            \"Temperature\",\n            \"Top-k\",\n            \"Top-p (nucleus)\",\n            \"Beam search\",\n            \"Greedy decoding\"\n        ],\n        prerequisites: [\n            \"GPT\"\n        ],\n        learnMore: [\n            {\n                title: \"Hugging Face: Text Generation\",\n                url: \"https://huggingface.co/blog/how-to-generate\"\n            }\n        ]\n    },\n    {\n        id: \"sentiment-analysis\",\n        concept: \"Sentiment Analysis\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"Determining the emotional tone of text — positive, negative, or neutral. One of the most common NLP applications. Modern approaches use fine-tuned BERT or zero-shot LLMs.\",\n        category: \"NLP & Language\",\n        difficulty: \"beginner\",\n        rank: 53,\n        keyTerms: [\n            \"Polarity\",\n            \"Aspect-based\",\n            \"Opinion mining\",\n            \"Valence\"\n        ],\n        prerequisites: [\n            \"NLP\"\n        ],\n        learnMore: [\n            {\n                title: \"Hugging Face: Sentiment Analysis\",\n                url: \"https://huggingface.co/tasks/text-classification\"\n            }\n        ],\n        realWorldApps: \"Brand monitoring, product reviews, social media analysis, customer feedback\"\n    },\n    {\n        id: \"machine-translation\",\n        concept: \"Machine Translation\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"Automatically translating text between languages. Evolved from rule-based → statistical → neural (seq2seq) → Transformer-based. Google Translate and DeepL use Transformer architectures.\",\n        category: \"NLP & Language\",\n        difficulty: \"intermediate\",\n        rank: 54,\n        keyTerms: [\n            \"Seq2seq\",\n            \"BLEU score\",\n            \"Encoder-decoder\",\n            \"Parallel corpus\"\n        ],\n        prerequisites: [\n            \"Transformer Architecture\"\n        ],\n        learnMore: [\n            {\n                title: \"Jay Alammar: Seq2Seq with Attention\",\n                url: \"https://jalammar.github.io/visualizing-neural-machine-translation-mechanics-of-seq2seq-models-with-attention/\"\n            }\n        ]\n    },\n    {\n        id: \"named-entity\",\n        concept: \"Named Entity Recognition (NER)\",\n        emoji: \"\\uD83D\\uDDE3️\",\n        description: \"Identifying and classifying named entities in text — persons, organizations, locations, dates, etc. A fundamental NLP task used in information extraction, search, and knowledge graphs.\",\n        category: \"NLP & Language\",\n        difficulty: \"intermediate\",\n        rank: 55,\n        keyTerms: [\n            \"Entity types\",\n            \"BIO tagging\",\n            \"SpaCy\",\n            \"Token classification\"\n        ],\n        prerequisites: [\n            \"NLP\"\n        ],\n        learnMore: [\n            {\n                title: \"spaCy NER Tutorial\",\n                url: \"https://spacy.io/usage/linguistic-features#named-entities\"\n            }\n        ],\n        realWorldApps: \"Document processing, search engines, news analysis, compliance\"\n    },\n    // === Computer Vision (56–65) ===\n    {\n        id: \"image-classification\",\n        concept: \"Image Classification\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"Assigning a label to an entire image. The task that started the deep learning revolution — AlexNet won ImageNet 2012 by a huge margin, proving deep learning works.\",\n        category: \"Computer Vision\",\n        difficulty: \"beginner\",\n        rank: 56,\n        keyTerms: [\n            \"ImageNet\",\n            \"Top-5 accuracy\",\n            \"Softmax\",\n            \"ResNet\",\n            \"EfficientNet\"\n        ],\n        prerequisites: [\n            \"CNN\"\n        ],\n        learnMore: [\n            {\n                title: \"Kaggle: Computer Vision\",\n                url: \"https://www.kaggle.com/learn/computer-vision\"\n            }\n        ]\n    },\n    {\n        id: \"object-detection\",\n        concept: \"Object Detection\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"Locating and classifying multiple objects within an image with bounding boxes. YOLO (You Only Look Once) made real-time detection practical. Used in autonomous driving, security, and robotics.\",\n        category: \"Computer Vision\",\n        difficulty: \"intermediate\",\n        rank: 57,\n        keyTerms: [\n            \"Bounding box\",\n            \"IoU\",\n            \"YOLO\",\n            \"Anchor boxes\",\n            \"Non-max suppression\"\n        ],\n        prerequisites: [\n            \"CNN\"\n        ],\n        learnMore: [\n            {\n                title: \"Ultralytics YOLO Docs\",\n                url: \"https://docs.ultralytics.com/\"\n            }\n        ],\n        realWorldApps: \"Self-driving cars, surveillance, retail analytics, medical imaging\"\n    },\n    {\n        id: \"semantic-segmentation\",\n        concept: \"Semantic Segmentation\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"Classifying every pixel in an image — assigning each pixel to a category. More granular than object detection. Used in autonomous driving, medical imaging, and satellite imagery.\",\n        category: \"Computer Vision\",\n        difficulty: \"intermediate\",\n        rank: 58,\n        keyTerms: [\n            \"Pixel-wise classification\",\n            \"U-Net\",\n            \"Mask\",\n            \"Instance segmentation\"\n        ],\n        prerequisites: [\n            \"CNN\"\n        ],\n        learnMore: [\n            {\n                title: \"Papers With Code: Segmentation\",\n                url: \"https://paperswithcode.com/task/semantic-segmentation\"\n            }\n        ]\n    },\n    {\n        id: \"yolo\",\n        concept: \"YOLO (You Only Look Once)\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"A real-time object detection system that processes the entire image in a single forward pass. YOLOv8 is the latest version — incredibly fast and accurate, making it the go-to for practical deployment.\",\n        category: \"Computer Vision\",\n        difficulty: \"intermediate\",\n        rank: 59,\n        keyTerms: [\n            \"Real-time detection\",\n            \"Grid cells\",\n            \"Confidence score\",\n            \"YOLOv8\"\n        ],\n        prerequisites: [\n            \"Object Detection\"\n        ],\n        learnMore: [\n            {\n                title: \"Ultralytics YOLOv8\",\n                url: \"https://github.com/ultralytics/ultralytics\"\n            }\n        ]\n    },\n    {\n        id: \"image-generation\",\n        concept: \"Image Generation\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"Creating new images from text descriptions or other inputs. Stable Diffusion, DALL-E, and Midjourney can generate photorealistic images from text prompts.\",\n        category: \"Computer Vision\",\n        difficulty: \"intermediate\",\n        rank: 60,\n        keyTerms: [\n            \"Text-to-image\",\n            \"Diffusion\",\n            \"CLIP guidance\",\n            \"Inpainting\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Stable Diffusion Guide\",\n                url: \"https://stability.ai/stable-diffusion\"\n            }\n        ]\n    },\n    {\n        id: \"neural-style-transfer\",\n        concept: \"Neural Style Transfer\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"Applying the artistic style of one image to the content of another — e.g., making your photo look like a Van Gogh painting. Uses CNN feature representations to separate content from style.\",\n        category: \"Computer Vision\",\n        difficulty: \"intermediate\",\n        rank: 61,\n        keyTerms: [\n            \"Content loss\",\n            \"Style loss\",\n            \"Gram matrix\",\n            \"Feature extraction\"\n        ],\n        prerequisites: [\n            \"CNN\"\n        ],\n        learnMore: [\n            {\n                title: \"A Neural Algorithm of Artistic Style\",\n                url: \"https://arxiv.org/abs/1508.06576\"\n            }\n        ]\n    },\n    {\n        id: \"deepfakes\",\n        concept: \"Deepfakes & Face Synthesis\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"AI-generated fake videos and images that swap faces or create entirely synthetic people. Uses GANs and diffusion models. Raises serious ethical concerns about misinformation.\",\n        category: \"Computer Vision\",\n        difficulty: \"advanced\",\n        rank: 62,\n        keyTerms: [\n            \"Face swap\",\n            \"Face reenactment\",\n            \"Detection methods\",\n            \"DeepFaceLab\"\n        ],\n        prerequisites: [\n            \"GANs\",\n            \"Image Generation\"\n        ],\n        learnMore: [\n            {\n                title: \"MIT Media Lab: Detecting Deepfakes\",\n                url: \"https://www.media.mit.edu/projects/detect-fakes/overview/\"\n            }\n        ]\n    },\n    {\n        id: \"time-series\",\n        concept: \"Time Series Forecasting\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"Predicting future values based on historical temporal data. Traditional methods (ARIMA) are being augmented by deep learning (LSTMs, Transformers). Critical for finance, weather, and demand planning.\",\n        category: \"Computer Vision\",\n        difficulty: \"intermediate\",\n        rank: 63,\n        keyTerms: [\n            \"ARIMA\",\n            \"Seasonality\",\n            \"Trend\",\n            \"Lag features\",\n            \"Prophet\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Facebook Prophet\",\n                url: \"https://facebook.github.io/prophet/\"\n            }\n        ],\n        realWorldApps: \"Stock prediction, weather forecasting, demand planning, energy grid\"\n    },\n    {\n        id: \"data\",\n        concept: \"Data — The Fuel of AI\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"AI is only as good as its data. Understanding data quality, bias, preprocessing, augmentation, and the data lifecycle is fundamental. 'More data beats better algorithms' — but only if the data is good.\",\n        category: \"Computer Vision\",\n        difficulty: \"beginner\",\n        rank: 64,\n        keyTerms: [\n            \"Data quality\",\n            \"Data augmentation\",\n            \"Data pipeline\",\n            \"Label noise\",\n            \"Data drift\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"Andrew Ng: Data-Centric AI\",\n                url: \"https://datacentricai.org/\"\n            }\n        ]\n    },\n    {\n        id: \"synthetic-data\",\n        concept: \"Synthetic Data\",\n        emoji: \"\\uD83D\\uDC41️\",\n        description: \"Artificially generated data that mimics real-world data. Used when real data is scarce, expensive, or privacy-sensitive. GANs and diffusion models can create realistic synthetic training data.\",\n        category: \"Computer Vision\",\n        difficulty: \"intermediate\",\n        rank: 65,\n        keyTerms: [\n            \"Data augmentation\",\n            \"Privacy-preserving\",\n            \"Distribution matching\"\n        ],\n        prerequisites: [\n            \"Data — The Fuel of AI\"\n        ],\n        learnMore: [\n            {\n                title: \"NVIDIA: Synthetic Data\",\n                url: \"https://developer.nvidia.com/blog/synthetic-data/\"\n            }\n        ]\n    },\n    // === Generative AI (66–75) ===\n    {\n        id: \"diffusion-models\",\n        concept: \"Diffusion Models\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"The architecture behind Stable Diffusion and DALL-E 3. Works by learning to reverse a noise-adding process — start from pure noise, gradually denoise to create an image. Replaced GANs as the dominant generative approach.\",\n        category: \"Generative AI\",\n        difficulty: \"advanced\",\n        rank: 66,\n        keyTerms: [\n            \"DDPM\",\n            \"Noise schedule\",\n            \"Denoising\",\n            \"U-Net backbone\",\n            \"Classifier-free guidance\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"DDPM Paper\",\n                url: \"https://arxiv.org/abs/2006.11239\"\n            },\n            {\n                title: \"Hugging Face Diffusion Course\",\n                url: \"https://huggingface.co/learn/diffusion-course\"\n            }\n        ]\n    },\n    {\n        id: \"gans\",\n        concept: \"GANs (Generative Adversarial Networks)\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"Two neural networks in competition: a generator creates fake data, a discriminator tries to detect it. The adversarial game produces increasingly realistic outputs. Introduced by Goodfellow in 2014.\",\n        category: \"Generative AI\",\n        difficulty: \"advanced\",\n        rank: 67,\n        keyTerms: [\n            \"Generator\",\n            \"Discriminator\",\n            \"Adversarial training\",\n            \"Mode collapse\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Original GAN Paper — Goodfellow\",\n                url: \"https://arxiv.org/abs/1406.2661\"\n            }\n        ]\n    },\n    {\n        id: \"vaes\",\n        concept: \"VAEs (Variational Autoencoders)\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"Generative models that learn a compressed latent space representation. Unlike GANs, VAEs can both generate AND encode data. The latent space is continuous, enabling smooth interpolation between outputs.\",\n        category: \"Generative AI\",\n        difficulty: \"advanced\",\n        rank: 68,\n        keyTerms: [\n            \"Latent space\",\n            \"KL divergence\",\n            \"Encoder\",\n            \"Decoder\",\n            \"Reparameterization\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Understanding VAEs — Towards Data Science\",\n                url: \"https://towardsdatascience.com/understanding-variational-autoencoders-vaes-f70510919f73\"\n            }\n        ]\n    },\n    {\n        id: \"stable-diffusion\",\n        concept: \"Stable Diffusion & Text-to-Image\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"The open-source text-to-image model that democratized AI art. Works in a compressed latent space (not pixel space) for efficiency. SDXL and SD3 produce photorealistic images from text prompts.\",\n        category: \"Generative AI\",\n        difficulty: \"intermediate\",\n        rank: 69,\n        keyTerms: [\n            \"Latent diffusion\",\n            \"CLIP text encoder\",\n            \"U-Net\",\n            \"ControlNet\",\n            \"LoRA\"\n        ],\n        prerequisites: [\n            \"Diffusion Models\"\n        ],\n        learnMore: [\n            {\n                title: \"Stable Diffusion WebUI\",\n                url: \"https://github.com/AUTOMATIC1111/stable-diffusion-webui\"\n            },\n            {\n                title: \"ComfyUI\",\n                url: \"https://github.com/comfyanonymous/ComfyUI\"\n            }\n        ],\n        realWorldApps: \"AI art, product mockups, game asset generation, marketing visuals\"\n    },\n    {\n        id: \"text-to-video\",\n        concept: \"Text-to-Video Generation\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"Generating video from text descriptions. Sora (OpenAI), Runway Gen-3, and Kling represent the frontier. Extends diffusion models with temporal consistency — the next frontier of generative AI.\",\n        category: \"Generative AI\",\n        difficulty: \"advanced\",\n        rank: 70,\n        keyTerms: [\n            \"Temporal consistency\",\n            \"Video diffusion\",\n            \"Frame interpolation\",\n            \"Sora\"\n        ],\n        prerequisites: [\n            \"Diffusion Models\"\n        ],\n        learnMore: [\n            {\n                title: \"OpenAI Sora Technical Report\",\n                url: \"https://openai.com/sora\"\n            }\n        ]\n    },\n    {\n        id: \"voice-cloning\",\n        concept: \"Voice Cloning & TTS\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"AI systems that can replicate any voice from a short sample, or generate natural-sounding speech from text. ElevenLabs and OpenAI's TTS models can produce indistinguishable synthetic voices.\",\n        category: \"Generative AI\",\n        difficulty: \"intermediate\",\n        rank: 71,\n        keyTerms: [\n            \"Text-to-speech\",\n            \"Voice synthesis\",\n            \"Speaker embedding\",\n            \"Prosody\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"OpenAI Whisper\",\n                url: \"https://github.com/openai/whisper\"\n            }\n        ],\n        realWorldApps: \"Audiobooks, dubbing, accessibility, virtual assistants, podcasting\"\n    },\n    {\n        id: \"music-generation\",\n        concept: \"AI Music Generation\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"Creating original music using AI — from background scores to full songs with vocals. Suno and Udio generate music from text prompts. Raises questions about creativity and copyright.\",\n        category: \"Generative AI\",\n        difficulty: \"intermediate\",\n        rank: 72,\n        keyTerms: [\n            \"Audio tokens\",\n            \"Music transformer\",\n            \"MIDI generation\",\n            \"Audio diffusion\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Google MusicLM\",\n                url: \"https://google-research.github.io/seanet/musiclm/examples/\"\n            }\n        ]\n    },\n    {\n        id: \"code-generation\",\n        concept: \"AI Code Generation\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"LLMs trained on code that can write, debug, and explain programs. GitHub Copilot, Claude, and GPT-4 can generate working code from natural language descriptions. Transforming software development.\",\n        category: \"Generative AI\",\n        difficulty: \"intermediate\",\n        rank: 73,\n        keyTerms: [\n            \"Code completion\",\n            \"Copilot\",\n            \"CodeLlama\",\n            \"Code review\",\n            \"Agentic coding\"\n        ],\n        prerequisites: [\n            \"GPT\"\n        ],\n        learnMore: [\n            {\n                title: \"GitHub Copilot\",\n                url: \"https://github.com/features/copilot\"\n            }\n        ],\n        realWorldApps: \"Software development, code review, documentation, debugging, prototyping\"\n    },\n    {\n        id: \"3d-generation\",\n        concept: \"3D Generation & NeRFs\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"Creating 3D objects and scenes from text or 2D images. Neural Radiance Fields (NeRFs) reconstruct 3D scenes from photos. Gaussian Splatting is the latest breakthrough for real-time 3D rendering.\",\n        category: \"Generative AI\",\n        difficulty: \"advanced\",\n        rank: 74,\n        keyTerms: [\n            \"NeRF\",\n            \"Gaussian splatting\",\n            \"3D reconstruction\",\n            \"Point clouds\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"NeRF Paper\",\n                url: \"https://arxiv.org/abs/2003.08934\"\n            }\n        ]\n    },\n    {\n        id: \"image-editing\",\n        concept: \"AI Image Editing & Inpainting\",\n        emoji: \"\\uD83C\\uDFA8\",\n        description: \"Using AI to edit specific parts of an image — removing objects, changing backgrounds, adding elements. Inpainting fills in missing or masked regions. Powered by diffusion models.\",\n        category: \"Generative AI\",\n        difficulty: \"intermediate\",\n        rank: 75,\n        keyTerms: [\n            \"Inpainting\",\n            \"Outpainting\",\n            \"Mask\",\n            \"ControlNet\",\n            \"Image-to-image\"\n        ],\n        prerequisites: [\n            \"Diffusion Models\"\n        ],\n        learnMore: [\n            {\n                title: \"ControlNet Paper\",\n                url: \"https://arxiv.org/abs/2302.05543\"\n            }\n        ]\n    },\n    // === Reinforcement Learning (76–85) ===\n    {\n        id: \"reinforcement-learning\",\n        concept: \"Reinforcement Learning (RL)\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"Learning through trial and error — an agent takes actions in an environment, receives rewards/penalties, and learns a policy to maximize cumulative reward. Behind AlphaGo and game-playing AI.\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"intermediate\",\n        rank: 76,\n        keyTerms: [\n            \"Agent\",\n            \"Environment\",\n            \"Reward\",\n            \"Policy\",\n            \"Episode\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Spinning Up in Deep RL — OpenAI\",\n                url: \"https://spinningup.openai.com/\"\n            },\n            {\n                title: \"David Silver's RL Course\",\n                url: \"https://www.youtube.com/playlist?list=PLqYmG7hTraZDM-OYHWgPebj2MfCFzFObQ\"\n            }\n        ]\n    },\n    {\n        id: \"q-learning\",\n        concept: \"Q-Learning & Deep Q-Networks (DQN)\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"Q-Learning estimates the value of actions in each state. Deep Q-Networks (DQN) use neural networks to approximate Q-values — DeepMind's DQN played Atari games at superhuman level (2013).\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"intermediate\",\n        rank: 77,\n        keyTerms: [\n            \"Q-value\",\n            \"Bellman equation\",\n            \"Experience replay\",\n            \"Target network\"\n        ],\n        prerequisites: [\n            \"Reinforcement Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"DQN Paper — DeepMind\",\n                url: \"https://arxiv.org/abs/1312.5602\"\n            }\n        ]\n    },\n    {\n        id: \"policy-gradient\",\n        concept: \"Policy Gradient & Actor-Critic\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"Policy gradient methods directly optimize the policy (action selection) rather than value estimates. Actor-Critic combines both: the actor selects actions, the critic evaluates them.\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"advanced\",\n        rank: 78,\n        keyTerms: [\n            \"REINFORCE\",\n            \"Advantage function\",\n            \"A2C\",\n            \"A3C\",\n            \"Baseline\"\n        ],\n        prerequisites: [\n            \"Q-Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"OpenAI Spinning Up: Policy Gradient\",\n                url: \"https://spinningup.openai.com/en/latest/algorithms/vpg.html\"\n            }\n        ]\n    },\n    {\n        id: \"ppo\",\n        concept: \"PPO (Proximal Policy Optimization)\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"The most widely used RL algorithm — simpler and more stable than predecessors. Used in RLHF to fine-tune ChatGPT, in robotics, and in game AI. Balances exploration with stable training.\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"advanced\",\n        rank: 79,\n        keyTerms: [\n            \"Clipping\",\n            \"Trust region\",\n            \"Surrogate objective\",\n            \"KL penalty\"\n        ],\n        prerequisites: [\n            \"Policy Gradient\"\n        ],\n        learnMore: [\n            {\n                title: \"PPO Paper — OpenAI\",\n                url: \"https://arxiv.org/abs/1707.06347\"\n            }\n        ]\n    },\n    {\n        id: \"markov-decision\",\n        concept: \"Markov Decision Process (MDP)\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"The mathematical framework underlying RL. Defines states, actions, transition probabilities, and rewards. The Markov property: the future depends only on the current state, not history.\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"intermediate\",\n        rank: 80,\n        keyTerms: [\n            \"State space\",\n            \"Action space\",\n            \"Transition function\",\n            \"Discount factor\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"Sutton & Barto: RL Book (Free)\",\n                url: \"http://incompleteideas.net/book/the-book-2nd.html\"\n            }\n        ]\n    },\n    {\n        id: \"reward-shaping\",\n        concept: \"Reward Design & Reward Hacking\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"Designing reward functions is RL's hardest problem. Reward hacking: agents find unintended shortcuts to maximize reward without actually solving the task. A core challenge in AI alignment.\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"advanced\",\n        rank: 81,\n        keyTerms: [\n            \"Sparse rewards\",\n            \"Reward shaping\",\n            \"Goodhart's law\",\n            \"Specification gaming\"\n        ],\n        prerequisites: [\n            \"Reinforcement Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"DeepMind: Specification Gaming\",\n                url: \"https://deepmindsafetyresearch.medium.com/specification-gaming-the-flip-side-of-ai-ingenuity-c85bdb0deeb4\"\n            }\n        ]\n    },\n    {\n        id: \"multi-agent-rl\",\n        concept: \"Multi-Agent Reinforcement Learning\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"Multiple agents learning simultaneously in a shared environment — they can cooperate, compete, or both. Adds complexity: each agent's optimal strategy depends on what others do.\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"advanced\",\n        rank: 82,\n        keyTerms: [\n            \"Nash equilibrium\",\n            \"Cooperative\",\n            \"Competitive\",\n            \"Self-play\"\n        ],\n        prerequisites: [\n            \"Reinforcement Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"OpenAI Five — Dota 2\",\n                url: \"https://openai.com/research/openai-five\"\n            }\n        ]\n    },\n    {\n        id: \"world-models\",\n        concept: \"World Models\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"AI that builds internal models of how the world works — predicting what happens next without actually experiencing it. LeCun's vision for the next paradigm: learning through observation, not just language.\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"advanced\",\n        rank: 83,\n        keyTerms: [\n            \"Predictive model\",\n            \"Imagination\",\n            \"Model-based RL\",\n            \"JEPA\"\n        ],\n        prerequisites: [\n            \"Reinforcement Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"LeCun: A Path Towards Autonomous Machine Intelligence\",\n                url: \"https://openreview.net/forum?id=BZ5a1r-kVsf\"\n            }\n        ]\n    },\n    {\n        id: \"sim-to-real\",\n        concept: \"Sim-to-Real Transfer\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"Training RL agents in simulation and deploying them in the real world. Overcomes the cost and danger of real-world training. Domain randomization helps bridge the gap between sim and reality.\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"advanced\",\n        rank: 84,\n        keyTerms: [\n            \"Domain randomization\",\n            \"Simulation\",\n            \"Reality gap\",\n            \"Digital twin\"\n        ],\n        prerequisites: [\n            \"Reinforcement Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"OpenAI: Sim-to-Real Robotics\",\n                url: \"https://openai.com/research/solving-rubiks-cube\"\n            }\n        ]\n    },\n    {\n        id: \"inverse-rl\",\n        concept: \"Inverse Reinforcement Learning\",\n        emoji: \"\\uD83C\\uDFAE\",\n        description: \"Learning the reward function from observing expert behavior — inferring WHAT the expert is optimizing, not just imitating their actions. Key for building AI that understands human preferences.\",\n        category: \"Reinforcement Learning\",\n        difficulty: \"advanced\",\n        rank: 85,\n        keyTerms: [\n            \"Reward inference\",\n            \"Expert demonstrations\",\n            \"Imitation learning\",\n            \"IRL\"\n        ],\n        prerequisites: [\n            \"Reinforcement Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Ng & Russell: IRL Paper\",\n                url: \"https://ai.stanford.edu/~ang/papers/icml00-irl.pdf\"\n            }\n        ]\n    },\n    // === MLOps & Infrastructure (86–95) ===\n    {\n        id: \"gpu-tpu\",\n        concept: \"GPU & TPU Computing\",\n        emoji: \"⚙️\",\n        description: \"GPUs (NVIDIA) and TPUs (Google) are the hardware that makes deep learning possible. Their parallel processing capabilities accelerate matrix operations by 100x+ versus CPUs.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"beginner\",\n        rank: 86,\n        keyTerms: [\n            \"CUDA\",\n            \"Tensor cores\",\n            \"A100\",\n            \"H100\",\n            \"TPUv5\",\n            \"Parallelism\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"NVIDIA CUDA Guide\",\n                url: \"https://developer.nvidia.com/cuda-zone\"\n            }\n        ]\n    },\n    {\n        id: \"model-deployment\",\n        concept: \"Model Deployment & Serving\",\n        emoji: \"⚙️\",\n        description: \"Getting trained models into production where they serve real users. Involves containerization (Docker), API frameworks (FastAPI), model servers (TensorRT, vLLM), and monitoring.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"intermediate\",\n        rank: 87,\n        keyTerms: [\n            \"Docker\",\n            \"FastAPI\",\n            \"TensorRT\",\n            \"vLLM\",\n            \"Latency\",\n            \"Throughput\"\n        ],\n        prerequisites: [\n            \"Training vs Inference\"\n        ],\n        learnMore: [\n            {\n                title: \"Made With ML — MLOps\",\n                url: \"https://madewithml.com/\"\n            }\n        ]\n    },\n    {\n        id: \"mlops\",\n        concept: \"MLOps (ML Operations)\",\n        emoji: \"⚙️\",\n        description: \"The practice of deploying, monitoring, and maintaining ML models in production. Combines ML, DevOps, and data engineering. The difference between a notebook prototype and a reliable production system.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"intermediate\",\n        rank: 88,\n        keyTerms: [\n            \"CI/CD for ML\",\n            \"Model registry\",\n            \"Feature store\",\n            \"A/B testing\",\n            \"Monitoring\"\n        ],\n        prerequisites: [\n            \"Model Deployment\"\n        ],\n        learnMore: [\n            {\n                title: \"Full Stack Deep Learning\",\n                url: \"https://fullstackdeeplearning.com/\"\n            },\n            {\n                title: \"Chip Huyen: Designing ML Systems\",\n                url: \"https://www.amazon.com/Designing-Machine-Learning-Systems-Production-Ready/dp/1098107969\"\n            }\n        ]\n    },\n    {\n        id: \"experiment-tracking\",\n        concept: \"Experiment Tracking\",\n        emoji: \"⚙️\",\n        description: \"Systematically logging hyperparameters, metrics, and artifacts for every ML experiment. Without it, ML research is unreproducible chaos. Weights & Biases and MLflow are the standards.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"beginner\",\n        rank: 89,\n        keyTerms: [\n            \"Hyperparameters\",\n            \"Metrics logging\",\n            \"Artifact tracking\",\n            \"Reproducibility\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Weights & Biases — Free Courses\",\n                url: \"https://wandb.ai/site/courses\"\n            }\n        ]\n    },\n    {\n        id: \"data-pipeline\",\n        concept: \"Data Pipelines & ETL\",\n        emoji: \"⚙️\",\n        description: \"Automated workflows for collecting, cleaning, transforming, and loading data for ML. The unsexy but critical infrastructure that makes everything else possible.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"intermediate\",\n        rank: 90,\n        keyTerms: [\n            \"ETL\",\n            \"Apache Airflow\",\n            \"dbt\",\n            \"Data warehouse\",\n            \"Feature store\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"Apache Airflow\",\n                url: \"https://airflow.apache.org/\"\n            }\n        ]\n    },\n    {\n        id: \"edge-ai\",\n        concept: \"Edge AI & On-Device ML\",\n        emoji: \"⚙️\",\n        description: \"Running AI models directly on devices (phones, IoT, cars) instead of in the cloud. Enables low-latency, privacy-preserving AI. Requires model compression and optimization.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"intermediate\",\n        rank: 91,\n        keyTerms: [\n            \"TensorFlow Lite\",\n            \"CoreML\",\n            \"ONNX\",\n            \"Edge TPU\",\n            \"Model optimization\"\n        ],\n        prerequisites: [\n            \"Model Quantization & Compression\"\n        ],\n        learnMore: [\n            {\n                title: \"TensorFlow Lite\",\n                url: \"https://www.tensorflow.org/lite\"\n            }\n        ],\n        realWorldApps: \"Smartphone cameras, smart speakers, autonomous vehicles, industrial IoT\"\n    },\n    {\n        id: \"federated-learning\",\n        concept: \"Federated Learning\",\n        emoji: \"⚙️\",\n        description: \"Training ML models across multiple devices/organizations without sharing raw data — each participant trains locally and shares only model updates. Preserves privacy while enabling collaborative learning.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"advanced\",\n        rank: 92,\n        keyTerms: [\n            \"Privacy-preserving\",\n            \"Aggregation\",\n            \"Non-IID data\",\n            \"Communication efficiency\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Google: Federated Learning\",\n                url: \"https://ai.googleblog.com/2017/04/federated-learning-collaborative.html\"\n            }\n        ]\n    },\n    {\n        id: \"distributed-training\",\n        concept: \"Distributed Training\",\n        emoji: \"⚙️\",\n        description: \"Training models across multiple GPUs or machines. Essential for frontier models — GPT-4 was trained on thousands of GPUs. Techniques: data parallelism, model parallelism, pipeline parallelism.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"advanced\",\n        rank: 93,\n        keyTerms: [\n            \"Data parallelism\",\n            \"Model parallelism\",\n            \"FSDP\",\n            \"DeepSpeed\",\n            \"Gradient sync\"\n        ],\n        prerequisites: [\n            \"GPU & TPU Computing\"\n        ],\n        learnMore: [\n            {\n                title: \"PyTorch Distributed Training\",\n                url: \"https://pytorch.org/tutorials/intermediate/ddp_tutorial.html\"\n            }\n        ]\n    },\n    {\n        id: \"model-versioning\",\n        concept: \"Model Versioning & Registry\",\n        emoji: \"⚙️\",\n        description: \"Tracking different versions of ML models with their metadata, performance metrics, and lineage. Essential for reproducibility and production deployment. MLflow Model Registry is the standard.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"intermediate\",\n        rank: 94,\n        keyTerms: [\n            \"Model registry\",\n            \"Version control\",\n            \"Lineage\",\n            \"Rollback\",\n            \"Staging\"\n        ],\n        prerequisites: [\n            \"Experiment Tracking\"\n        ],\n        learnMore: [\n            {\n                title: \"MLflow Model Registry\",\n                url: \"https://mlflow.org/docs/latest/model-registry.html\"\n            }\n        ]\n    },\n    {\n        id: \"monitoring\",\n        concept: \"ML Monitoring & Observability\",\n        emoji: \"⚙️\",\n        description: \"Watching ML models in production for degradation. Models decay over time as data distributions shift. Monitoring detects data drift, concept drift, and performance drops before they impact users.\",\n        category: \"MLOps & Infrastructure\",\n        difficulty: \"intermediate\",\n        rank: 95,\n        keyTerms: [\n            \"Data drift\",\n            \"Concept drift\",\n            \"Model degradation\",\n            \"Alerting\",\n            \"Retraining\"\n        ],\n        prerequisites: [\n            \"Model Deployment\"\n        ],\n        learnMore: [\n            {\n                title: \"Evidently AI — ML Monitoring\",\n                url: \"https://www.evidentlyai.com/\"\n            }\n        ]\n    },\n    // === AI Agents & Applications (96–105) ===\n    {\n        id: \"ai-agents\",\n        concept: \"AI Agents\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"AI systems that can plan, use tools, browse the web, write code, and complete multi-step tasks autonomously. The hottest frontier in AI (2025–2026). LangGraph, CrewAI, and AutoGen are leading frameworks.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"intermediate\",\n        rank: 96,\n        keyTerms: [\n            \"Tool use\",\n            \"Planning\",\n            \"ReAct\",\n            \"Reasoning loop\",\n            \"Autonomy\"\n        ],\n        prerequisites: [\n            \"Prompt Engineering\",\n            \"GPT\"\n        ],\n        learnMore: [\n            {\n                title: \"Anthropic: Building Effective Agents\",\n                url: \"https://docs.anthropic.com/en/docs/build-with-claude/agentic\"\n            },\n            {\n                title: \"LangGraph Documentation\",\n                url: \"https://langchain-ai.github.io/langgraph/\"\n            }\n        ],\n        realWorldApps: \"Coding assistants, research automation, customer service, data analysis\"\n    },\n    {\n        id: \"tool-use\",\n        concept: \"Tool Use & Function Calling\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"LLMs that can call external tools — APIs, databases, calculators, web browsers. Transforms LLMs from text generators into action-taking agents. OpenAI function calling and Claude tool use are leading implementations.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"intermediate\",\n        rank: 97,\n        keyTerms: [\n            \"Function calling\",\n            \"API integration\",\n            \"MCP\",\n            \"Tool selection\"\n        ],\n        prerequisites: [\n            \"AI Agents\"\n        ],\n        learnMore: [\n            {\n                title: \"OpenAI: Function Calling\",\n                url: \"https://platform.openai.com/docs/guides/function-calling\"\n            }\n        ]\n    },\n    {\n        id: \"autonomous-vehicles\",\n        concept: \"Autonomous Vehicles & Robotics\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"Self-driving cars and intelligent robots that perceive, plan, and act in the physical world. Combines computer vision, RL, sensor fusion, and path planning. Tesla, Waymo, and Figure lead the field.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"advanced\",\n        rank: 98,\n        keyTerms: [\n            \"Lidar\",\n            \"Sensor fusion\",\n            \"Path planning\",\n            \"SLAM\",\n            \"End-to-end driving\"\n        ],\n        prerequisites: [\n            \"Computer Vision\",\n            \"Reinforcement Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Waymo Research\",\n                url: \"https://waymo.com/research/\"\n            }\n        ]\n    },\n    {\n        id: \"recommendation-systems\",\n        concept: \"Recommendation Systems\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"AI that suggests content, products, or connections based on user behavior and preferences. Powers Netflix, YouTube, Amazon, and TikTok. Uses collaborative filtering, content-based, and hybrid approaches.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"intermediate\",\n        rank: 99,\n        keyTerms: [\n            \"Collaborative filtering\",\n            \"Content-based\",\n            \"Matrix factorization\",\n            \"Cold start\"\n        ],\n        prerequisites: [\n            \"Machine Learning\",\n            \"Embeddings\"\n        ],\n        learnMore: [\n            {\n                title: \"Google: Recommendation Systems Course\",\n                url: \"https://developers.google.com/machine-learning/recommendation\"\n            }\n        ]\n    },\n    {\n        id: \"drug-discovery\",\n        concept: \"AI-Driven Drug Discovery\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"Using AI to identify, design, and optimize drug candidates — dramatically accelerating the traditional 10-15 year drug development cycle. AlphaFold solved protein folding; Insilico Medicine created the first AI-designed drug in clinical trials.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"advanced\",\n        rank: 100,\n        keyTerms: [\n            \"Protein folding\",\n            \"AlphaFold\",\n            \"Molecular generation\",\n            \"Drug target\"\n        ],\n        prerequisites: [\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"AlphaFold — DeepMind\",\n                url: \"https://alphafold.ebi.ac.uk/\"\n            }\n        ]\n    },\n    {\n        id: \"xai\",\n        concept: \"Explainable AI (XAI)\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"Techniques to make AI decisions interpretable by humans. SHAP and LIME explain individual predictions. Critical for healthcare, finance, and legal applications where decisions must be justified.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"intermediate\",\n        rank: 101,\n        keyTerms: [\n            \"SHAP\",\n            \"LIME\",\n            \"Feature importance\",\n            \"Attention visualization\",\n            \"Interpretability\"\n        ],\n        prerequisites: [\n            \"Machine Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"SHAP Documentation\",\n                url: \"https://shap.readthedocs.io/\"\n            },\n            {\n                title: \"Christoph Molnar: Interpretable ML (Free Book)\",\n                url: \"https://christophm.github.io/interpretable-ml-book/\"\n            }\n        ]\n    },\n    {\n        id: \"search-ranking\",\n        concept: \"AI-Powered Search & Ranking\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"Using ML to improve search results and ranking. Moved from keyword matching to semantic understanding. BERT transformed Google Search. Vector search enables meaning-based retrieval.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"intermediate\",\n        rank: 102,\n        keyTerms: [\n            \"Semantic search\",\n            \"Learning to rank\",\n            \"BM25\",\n            \"Cross-encoder\",\n            \"Bi-encoder\"\n        ],\n        prerequisites: [\n            \"Embeddings\",\n            \"BERT\"\n        ],\n        learnMore: [\n            {\n                title: \"Pinecone: Semantic Search\",\n                url: \"https://www.pinecone.io/learn/semantic-search/\"\n            }\n        ]\n    },\n    {\n        id: \"conversational-ai\",\n        concept: \"Conversational AI & Chatbots\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"AI systems for natural dialogue — from simple rule-based chatbots to LLM-powered assistants. Key challenges: maintaining context, handling ambiguity, knowing when to escalate to humans.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"intermediate\",\n        rank: 103,\n        keyTerms: [\n            \"Dialog management\",\n            \"Intent recognition\",\n            \"Slot filling\",\n            \"Conversation memory\"\n        ],\n        prerequisites: [\n            \"NLP\",\n            \"GPT\"\n        ],\n        learnMore: [\n            {\n                title: \"Rasa Documentation\",\n                url: \"https://rasa.com/docs/\"\n            }\n        ]\n    },\n    {\n        id: \"medical-ai\",\n        concept: \"AI in Healthcare & Medical Imaging\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"AI for diagnosis, treatment planning, drug discovery, and medical imaging. CNNs match or exceed radiologists for certain diagnoses. Faces unique challenges: regulation, liability, bias in clinical data.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"advanced\",\n        rank: 104,\n        keyTerms: [\n            \"Medical imaging\",\n            \"Clinical NLP\",\n            \"FDA approval\",\n            \"Diagnostic AI\"\n        ],\n        prerequisites: [\n            \"CNN\",\n            \"Deep Learning\"\n        ],\n        learnMore: [\n            {\n                title: \"Google Health AI\",\n                url: \"https://health.google/\"\n            }\n        ]\n    },\n    {\n        id: \"creative-ai\",\n        concept: \"AI for Creative Industries\",\n        emoji: \"\\uD83E\\uDD16\",\n        description: \"AI tools transforming art, music, writing, film, and design. From AI-assisted writing to AI-generated music and video. Raises questions about authorship, copyright, and the future of creative work.\",\n        category: \"AI Agents & Applications\",\n        difficulty: \"beginner\",\n        rank: 105,\n        keyTerms: [\n            \"AI art\",\n            \"AI writing\",\n            \"Generative design\",\n            \"Copyright\",\n            \"Human-AI collaboration\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"Runway ML\",\n                url: \"https://runwayml.com/\"\n            }\n        ]\n    },\n    // === Safety, Ethics & Governance (106–110) ===\n    {\n        id: \"ai-alignment\",\n        concept: \"AI Alignment\",\n        emoji: \"\\uD83D\\uDEE1️\",\n        description: \"The challenge of ensuring AI systems pursue goals beneficial to humans. The most important unsolved problem in AI. Includes technical approaches (RLHF, Constitutional AI) and governance frameworks.\",\n        category: \"Safety, Ethics & Governance\",\n        difficulty: \"intermediate\",\n        rank: 106,\n        keyTerms: [\n            \"Value alignment\",\n            \"Outer alignment\",\n            \"Inner alignment\",\n            \"Reward hacking\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"AI Safety Fundamentals\",\n                url: \"https://aisafetyfundamentals.com/\"\n            },\n            {\n                title: \"Anthropic: Core Views on AI Safety\",\n                url: \"https://www.anthropic.com/research\"\n            }\n        ]\n    },\n    {\n        id: \"ai-bias\",\n        concept: \"AI Bias & Fairness\",\n        emoji: \"\\uD83D\\uDEE1️\",\n        description: \"AI systems can perpetuate and amplify societal biases present in training data. Understanding, measuring, and mitigating bias is critical for responsible AI deployment.\",\n        category: \"Safety, Ethics & Governance\",\n        difficulty: \"intermediate\",\n        rank: 107,\n        keyTerms: [\n            \"Training data bias\",\n            \"Algorithmic fairness\",\n            \"Disparate impact\",\n            \"Fairlearn\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"Fairlearn Documentation\",\n                url: \"https://fairlearn.org/\"\n            },\n            {\n                title: \"Weapons of Math Destruction (Book)\",\n                url: \"https://www.amazon.com/Weapons-Math-Destruction-Increases-Inequality/dp/0553418815\"\n            }\n        ],\n        realWorldApps: \"Hiring algorithms, criminal justice, lending decisions, healthcare\"\n    },\n    {\n        id: \"hallucination\",\n        concept: \"AI Hallucinations\",\n        emoji: \"\\uD83D\\uDEE1️\",\n        description: \"When AI generates confident but factually incorrect or fabricated information. A fundamental limitation of current LLMs — they predict plausible text, not truthful text. RAG and grounding techniques help reduce it.\",\n        category: \"Safety, Ethics & Governance\",\n        difficulty: \"beginner\",\n        rank: 108,\n        keyTerms: [\n            \"Confabulation\",\n            \"Grounding\",\n            \"Factual accuracy\",\n            \"RAG as mitigation\"\n        ],\n        prerequisites: [\n            \"GPT\"\n        ],\n        learnMore: [\n            {\n                title: \"Anthropic: Reducing Hallucinations\",\n                url: \"https://docs.anthropic.com/en/docs/build-with-claude/prompt-engineering/reduce-hallucinations\"\n            }\n        ]\n    },\n    {\n        id: \"red-teaming\",\n        concept: \"Red Teaming AI Systems\",\n        emoji: \"\\uD83D\\uDEE1️\",\n        description: \"Systematically testing AI systems by trying to make them fail, produce harmful outputs, or bypass safety measures. Essential for finding vulnerabilities before deployment. Both manual and automated approaches.\",\n        category: \"Safety, Ethics & Governance\",\n        difficulty: \"intermediate\",\n        rank: 109,\n        keyTerms: [\n            \"Jailbreaking\",\n            \"Adversarial attacks\",\n            \"Safety evaluation\",\n            \"Prompt injection\"\n        ],\n        prerequisites: [\n            \"Prompt Engineering\"\n        ],\n        learnMore: [\n            {\n                title: \"Anthropic: Red Teaming\",\n                url: \"https://www.anthropic.com/research/red-teaming\"\n            }\n        ]\n    },\n    {\n        id: \"ai-regulation\",\n        concept: \"AI Regulation & Governance\",\n        emoji: \"\\uD83D\\uDEE1️\",\n        description: \"The emerging legal and policy landscape for AI. The EU AI Act (2024) is the first comprehensive AI law. Understanding regulation is now a career advantage — every AI team needs someone who understands compliance.\",\n        category: \"Safety, Ethics & Governance\",\n        difficulty: \"beginner\",\n        rank: 110,\n        keyTerms: [\n            \"EU AI Act\",\n            \"Risk categories\",\n            \"Compliance\",\n            \"Transparency requirements\"\n        ],\n        prerequisites: [],\n        learnMore: [\n            {\n                title: \"EU AI Act Overview\",\n                url: \"https://artificialintelligenceact.eu/\"\n            },\n            {\n                title: \"NIST AI Risk Management Framework\",\n                url: \"https://www.nist.gov/artificial-intelligence/executive-order-safe-secure-and-trustworthy-artificial-intelligence\"\n            }\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/aiEncyclopedia.ts\n");

